def process_data_lbyl(config_data, key):
    if not isinstance(config_data, dict):
        return "Geçersiz yapılandırma verisi tipi."

    if key in config_data:
        value = config_data[key]
        return f"'{key}' anahtarı için değer: {value}"
    else:
        return f"'{key}' anahtarı yapılandırmada bulunamadı."
